package com.careeros.documents.infrastructure;import com.careeros.documents.application.ResumeDocumentPort;import com.fasterxml.jackson.databind.*;import org.springframework.stereotype.Component;import java.nio.file.*;import java.util.*;@Component public class PythonDocxAdapter implements ResumeDocumentPort{private final ProcessRunner runner;private final ResumeDocumentProperties p;private final ObjectMapper json;public PythonDocxAdapter(ProcessRunner r,ResumeDocumentProperties p,ObjectMapper j){runner=r;this.p=p;json=j;}public Extracted extract(Path source){check(source);var result=runner.run(List.of(p.pythonPath(),"scripts/resume_docx.py","extract","--source",source.toString()),null,p.processTimeout());try{JsonNode n=json.readTree(result.stdout());List<String>b=new ArrayList<>();n.path("bullets").forEach(x->b.add(x.asText()));return new Extracted(n.path("text").asText(),b);}catch(Exception e){throw new IllegalStateException("Invalid python-docx extraction response",e);}}public Path generate(Path source,Path target,List<String>bullets){check(source);try{Files.createDirectories(target.getParent());String input=json.writeValueAsString(Map.of("bullets",bullets));runner.run(List.of(p.pythonPath(),"scripts/resume_docx.py","generate","--source",source.toString(),"--target",target.toString()),input,p.processTimeout());if(!Files.isRegularFile(target))throw new IllegalStateException("DOCX was not created");return target;}catch(java.io.IOException e){throw new IllegalStateException("Unable to prepare resume output",e);}}private void check(Path p){if(!Files.isRegularFile(p))throw new IllegalStateException("Master resume not found: "+p);}}
